from flask import Flask, request, session, redirect, url_for
import xml.etree.ElementTree as ET
import base64
import zlib

app = Flask(__name__)
app.secret_key = 'your_secret_key'

def parse_saml_response(saml_response):
    try:
        decoded_data = base64.b64decode(saml_response)
        inflated_data = zlib.decompress(decoded_data, -15)
        root = ET.fromstring(inflated_data)
        return root
    except Exception as e:
        print(f"Error parsing SAML response: {e}")
        return None

def extract_user_attributes(assertion):
    attributes = {}
    for attr_statement in assertion.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}AttributeStatement'):
        for attribute in attr_statement.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
            attr_name = attribute.get('Name')
            attr_value = attribute.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue').text
            attributes[attr_name] = attr_value
    return attributes

@app.route('/sso/acs', methods=['POST'])
def acs():
    saml_response = request.form.get('SAMLResponse')
    if not saml_response:
        return "No SAML Response found", 400

    saml_root = parse_saml_response(saml_response)
    if saml_root is None:
        return "Invalid SAML Response", 400

    assertion = saml_root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
    if assertion is None:
        return "No Assertion found in SAML Response", 400

    user_attributes = extract_user_attributes(assertion)
    if not user_attributes:
        return "No user attributes found", 400

    session['user'] = user_attributes
    return redirect(url_for('welcome'))

@app.route('/welcome')
def welcome():
    if 'user' not in session:
        return redirect(url_for('login'))
    return f"Welcome, {session['user'].get('username', 'User')}!"

@app.route('/login')
def login():
    return "Please log in via your Identity Provider."

if __name__ == '__main__':
    app.run(ssl_context='adhoc')